Below are snippets you can paste into `macos/Lex.swift`. They follow the revised plan: **modifiable event tap**, **passthrough callback**, **print observed characters**, and **prepare synthetic event source/tag for later consuming/replacement logic**.

### 1. Add import if needed

Near the top:

```swift
import CoreGraphics
```

Current file already imports `Carbon` and `SwiftUI`. If `CGEvent`, `CFMachPort`, or `CGEventSource` already resolve without this, you can omit it.

### 2. Add synthetic-event tag constant

Near the existing hot-key constant:

```swift
private let synthetic_event_source_user_data: Int64 = 0x4C4558
```

This matches the prototype’s idea of tagging Lex-generated events so the tap can ignore them later.

### 3. Add stored properties to `AppDelegate`

Inside `AppDelegate`, near the other private state:

```swift
private var event_tap: CFMachPort?
private var event_tap_run_loop_source: CFRunLoopSource?
private var synthetic_event_source: CGEventSource?
```

### 4. Wire launch / shutdown lifecycle

In `applicationDidFinishLaunching`, replace the placeholder comment:

```swift
initialize_synthetic_event_source()
start_event_tap()
```

So the launch body becomes conceptually:

```swift
func applicationDidFinishLaunching(_ notification: Notification) {
    print("Activated.")
    install_signal_handler(SIGINT)
    install_signal_handler(SIGTERM)
    initialize_engine_state()
    register_toggle_input_mode_hot_key()
    initialize_synthetic_event_source()
    start_event_tap()
}
```

In `applicationWillTerminate`, replace the stop placeholder:

```swift
stop_event_tap()
destroy_synthetic_event_source()
```

Conceptually:

```swift
func applicationWillTerminate(_ notification: Notification) {
    print("Shutting down...")
    stop_event_tap()
    destroy_synthetic_event_source()
    unregister_toggle_input_mode_hot_key()
    destroy_engine_state()
    signal_sources.removeAll()
}
```

### 5. Add synthetic source lifecycle helpers

Inside `AppDelegate`:

```swift
private func initialize_synthetic_event_source() {
    precondition(synthetic_event_source == nil)

    let source = CGEventSource(stateID: .privateState)
    source?.userData = synthetic_event_source_user_data
    synthetic_event_source = source
}

private func destroy_synthetic_event_source() {
    synthetic_event_source = nil
}
```

For this checkpoint, the source is not posting anything yet. It is just ready for the next phase.

### 6. Add event tap start / stop helpers

Inside `AppDelegate`:

```swift
private func start_event_tap() {
    precondition(event_tap == nil)
    precondition(event_tap_run_loop_source == nil)

    let event_mask =
        (1 << CGEventType.keyDown.rawValue) |
        (1 << CGEventType.tapDisabledByTimeout.rawValue) |
        (1 << CGEventType.tapDisabledByUserInput.rawValue)

    let self_pointer = Unmanaged.passUnretained(self).toOpaque()

    guard let tap = CGEvent.tapCreate(
        tap: .cgSessionEventTap,
        place: .headInsertEventTap,
        options: .defaultTap,
        eventsOfInterest: CGEventMask(event_mask),
        callback: lex_event_tap_callback,
        userInfo: self_pointer
    ) else {
        print("Failed to create event tap. Input Monitoring or Accessibility permission may be required.")
        return
    }

    let run_loop_source = CFMachPortCreateRunLoopSource(kCFAllocatorDefault, tap, 0)

    event_tap = tap
    event_tap_run_loop_source = run_loop_source

    CFRunLoopAddSource(CFRunLoopGetCurrent(), run_loop_source, .commonModes)
    CGEvent.tapEnable(tap: tap, enable: true)

    print("Event tap started.")
}

private func stop_event_tap() {
    guard let tap = event_tap else {
        return
    }

    CGEvent.tapEnable(tap: tap, enable: false)

    if let run_loop_source = event_tap_run_loop_source {
        CFRunLoopRemoveSource(CFRunLoopGetCurrent(), run_loop_source, .commonModes)
    }

    CFMachPortInvalidate(tap)

    event_tap_run_loop_source = nil
    event_tap = nil

    print("Event tap stopped.")
}
```

### 7. Add small helper for disabled-tap recovery

Inside `AppDelegate`:

```swift
func enable_event_tap() {
    guard let event_tap else {
        return
    }

    CGEvent.tapEnable(tap: event_tap, enable: true)
}
```

This lets the C callback re-enable the tap without exposing the stored property directly.

### 8. Add the callback function

Place this outside `AppDelegate`, for example after the class definition and before `enum InputMode`.

```swift
private func lex_event_tap_callback(
    proxy: CGEventTapProxy,
    type event_type: CGEventType,
    event: CGEvent,
    userInfo: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    guard let userInfo else {
        return Unmanaged.passUnretained(event)
    }

    let app_delegate = Unmanaged<AppDelegate>
        .fromOpaque(userInfo)
        .takeUnretainedValue()

    if event_type == .tapDisabledByTimeout || event_type == .tapDisabledByUserInput {
        app_delegate.enable_event_tap()
        return Unmanaged.passUnretained(event)
    }

    guard event_type == .keyDown else {
        return Unmanaged.passUnretained(event)
    }

    if event.getIntegerValueField(.eventSourceUserData) == synthetic_event_source_user_data {
        return Unmanaged.passUnretained(event)
    }

    var character_count = 0
    event.keyboardGetUnicodeString(
        maxStringLength: 0,
        actualStringLength: &character_count,
        unicodeString: nil
    )

    if character_count > 0 {
        var characters = [UniChar](repeating: 0, count: character_count)
        event.keyboardGetUnicodeString(
            maxStringLength: character_count,
            actualStringLength: &character_count,
            unicodeString: &characters
        )

        let string = String(
            utf16CodeUnits: characters,
            count: character_count
        )

        print("Input character: \(string)")
    } else {
        let key_code = event.getIntegerValueField(.keyboardEventKeycode)
        print("Input key code: \(key_code)")
    }

    return Unmanaged.passUnretained(event)
}
```

Notes:

- This is a **modifiable** tap because it uses `.defaultTap`, not listen-only.
- It still **passes every event through**.
- Later, consuming is done by returning `nil`.
- Later, synthetic text/backspace events can be posted using `synthetic_event_source`.
- The callback ignores Lex-generated synthetic events by checking `.eventSourceUserData`.

Use the static method as a qualified function reference:

```swift
callback: AppDelegate.event_tap_callback,
```

So inside `start_event_tap()`:

```swift
guard let tap = CGEvent.tapCreate(
    tap: .cgSessionEventTap,
    place: .headInsertEventTap,
    options: .defaultTap,
    eventsOfInterest: CGEventMask(event_mask),
    callback: AppDelegate.event_tap_callback,
    userInfo: self_pointer
) else {
    print("Failed to create event tap. Input Monitoring or Accessibility permission may be required.")
    return
}
```

Then define the callback inside `AppDelegate` as a `static` method:

```swift
private static func event_tap_callback(
    proxy: CGEventTapProxy,
    type event_type: CGEventType,
    event: CGEvent,
    userInfo: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    guard let userInfo else {
        return Unmanaged.passUnretained(event)
    }

    let app_delegate = Unmanaged<AppDelegate>
        .fromOpaque(userInfo)
        .takeUnretainedValue()

    if event_type == .tapDisabledByTimeout || event_type == .tapDisabledByUserInput {
        app_delegate.enable_event_tap()
        return Unmanaged.passUnretained(event)
    }

    guard event_type == .keyDown else {
        return Unmanaged.passUnretained(event)
    }

    if event.getIntegerValueField(.eventSourceUserData) == synthetic_event_source_user_data {
        return Unmanaged.passUnretained(event)
    }

    var character_count = 0
    event.keyboardGetUnicodeString(
        maxStringLength: 0,
        actualStringLength: &character_count,
        unicodeString: nil
    )

    if character_count > 0 {
        var characters = [UniChar](repeating: 0, count: character_count)
        event.keyboardGetUnicodeString(
            maxStringLength: character_count,
            actualStringLength: &character_count,
            unicodeString: &characters
        )

        let string = String(
            utf16CodeUnits: characters,
            count: character_count
        )

        print("Input character: \(string)")
    } else {
        let key_code = event.getIntegerValueField(.keyboardEventKeycode)
        print("Input key code: \(key_code)")
    }

    return Unmanaged.passUnretained(event)
}
```

Important detail: because it is `static`, it cannot directly access instance properties like `event_tap`. That is why it recovers the actual instance from `userInfo`:

```swift
let app_delegate = Unmanaged<AppDelegate>
    .fromOpaque(userInfo)
    .takeUnretainedValue()
```

Then instance methods/properties are accessed through `app_delegate`, for example:

```swift
app_delegate.enable_event_tap()
```
